#include <ap_int.h>
#include <cstdio>
#include <cstring>
#include <cstdlib>
#include <cmath>
#include <algorithm>

// AUTO-GENERATED by FHCA_main/tools/gen_vitis_tb.py — 请勿手工编辑。
// 重新生成: python tools/gen_vitis_tb.py --output-dir /home/hwx/HCA/FPGA-SNN/FastHCA/gen-mlir2hls/cognisnn/output \\
//   --t 5 --num-classes 11 --input-shape 2,128,128 --num-images 2
// hls.cpp: /home/hwx/HCA/FPGA-SNN/FastHCA/gen-mlir2hls/cognisnn/output/hls.cpp
// 权重表: /home/hwx/HCA/FPGA-SNN/FastHCA/gen-mlir2hls/cognisnn/output/gen/host/mem_init_ext.cpp（byte offset，勿再乘 4）

void control(ap_int<32>*, ap_int<32>*, ap_int<32>*);
void control_t(ap_int<32>*, ap_int<32>*, ap_int<32>*, const ap_int<32>*, float*, long, int, int, long);

#define DDR_SIZE      12864384    // from hls.cpp
#define NUM_CLASSES   11
#define T_STEPS       5
#define OUTPUT_OFFSET 8388608     // element offset (arg0-based), x4 = byte offset
#define INPUT_OFFSET  0      // element offset (arg0-based)
#define INPUT_SIZE    (5*(2*128*128))

struct WeightInfo {
    const char* filename;
    size_t byte_offset;
    size_t byte_size;
};

// 18 weight entries from gen/host/mem_init_ext.cpp
WeightInfo WEIGHTS[] = {
    {"data/const_34.bin", 50793984, 1408},
    {"data/const_35.bin", 50830848, 44},
    {"data/const_33.bin", 50867712, 36864},
    {"data/const_32.bin", 50904576, 36864},
    {"data/const_31.bin", 50941440, 36864},
    {"data/const_30.bin", 50978304, 36864},
    {"data/const_29.bin", 51015168, 36864},
    {"data/const_28.bin", 51052032, 36864},
    {"data/const_27.bin", 51088896, 36864},
    {"data/const_26.bin", 51125760, 36864},
    {"data/const_25.bin", 51162624, 36864},
    {"data/const_24.bin", 51199488, 36864},
    {"data/const_23.bin", 51236352, 36864},
    {"data/const_22.bin", 51273216, 36864},
    {"data/const_21.bin", 51310080, 36864},
    {"data/const_20.bin", 51346944, 36864},
    {"data/const_18.bin", 51383808, 128},
    {"data/const_19.bin", 51420672, 2304},
};

const int NUM_WEIGHTS = 18;
const int NUM_IMAGES = 2;

int main() {
    printf("============================================================\n");
    printf("cognisnn C-Simulation (T=%d)\n", T_STEPS);
    printf("============================================================\n");
    printf("DDR_SIZE = %d elements (%.1f MB)\n", DDR_SIZE, DDR_SIZE * 4.0 / 1024 / 1024);
    printf("Weights = %d files\n\n", NUM_WEIGHTS);

    ap_int<32>* ddr = (ap_int<32>*)malloc(DDR_SIZE * sizeof(ap_int<32>));
    float* input_buf = (float*)malloc(INPUT_SIZE * sizeof(float));
    ap_int<32>* staging = (ap_int<32>*)malloc(INPUT_SIZE * sizeof(ap_int<32>));
    if (!ddr || !input_buf || !staging) { printf("FATAL: malloc failed\n"); return 1; }

    int correct = 0;
    int hls_pt_match = 0;
    float total_l2 = 0.0f;

    for (int idx = 0; idx < NUM_IMAGES; idx++) {
        // Load true label
        char path[256];
        snprintf(path, 256, "test_images/label_%d.bin", idx);
        FILE* fp = fopen(path, "rb");
        if (!fp) { printf("FATAL: missing %s\n", path); return 1; }
        int true_label;
        fread(&true_label, sizeof(int), 1, fp);
        fclose(fp);

        // Load input image (T=5 帧连续 (per-step input))
        snprintf(path, 256, "test_images/test_image_%d.bin", idx);
        fp = fopen(path, "rb");
        if (!fp) { printf("FATAL: missing %s\n", path); return 1; }
        fread(input_buf, sizeof(float), INPUT_SIZE, fp);
        fclose(fp);

        // Load expected (PyTorch T=5, mean of per-step outputs)
        snprintf(path, 256, "test_images/expected_output_%d.bin", idx);
        float expected_output[NUM_CLASSES];
        fp = fopen(path, "rb");
        if (!fp) { printf("FATAL: missing %s\n", path); return 1; }
        fread(expected_output, sizeof(float), NUM_CLASSES, fp);
        fclose(fp);

        printf("\n--- Image %d/2 (true label=%d) ---\n", idx + 1, true_label);

        // Zero DDR (resets LIF membrane states) and load weights once
        memset(ddr, 0, DDR_SIZE * sizeof(ap_int<32>));
        for (int w = 0; w < NUM_WEIGHTS; w++) {
            fp = fopen(WEIGHTS[w].filename, "rb");
            if (!fp) { printf("FATAL: Cannot open %s\n", WEIGHTS[w].filename); return 1; }
            fread((char*)ddr + WEIGHTS[w].byte_offset, 1, WEIGHTS[w].byte_size, fp);
            fclose(fp);
        }

        // T-step loop: membrane states persist in DDR top_level buffers
        // across control() calls (mirrors spikingjelly reset_net + T-loop).
        // FHCA v1.4: on-chip T-step loop via control_t() (per-step input)
        memcpy(staging, input_buf, INPUT_SIZE * sizeof(float));
        float out_frames[T_STEPS * NUM_CLASSES];
        control_t(ddr, ddr, ddr, staging, out_frames,
                  OUTPUT_OFFSET, NUM_CLASSES, T_STEPS, INPUT_SIZE / T_STEPS);

        // spikingjelly convention: mean over T steps
        float hls_output[NUM_CLASSES] = {{0.0f}};
        for (int t = 0; t < T_STEPS; t++)
            for (int i = 0; i < NUM_CLASSES; i++)
                hls_output[i] += out_frames[t * NUM_CLASSES + i] / T_STEPS;


        int hls_pred = 0;
        for (int i = 1; i < NUM_CLASSES; i++)
            if (hls_output[i] > hls_output[hls_pred]) hls_pred = i;

        // PyTorch prediction
        int pt_pred = 0;
        for (int i = 1; i < NUM_CLASSES; i++)
            if (expected_output[i] > expected_output[pt_pred]) pt_pred = i;

        // Compare HLS vs PyTorch
        float l2 = 0.0f, max_diff = 0.0f;
        for (int i = 0; i < NUM_CLASSES; i++) {
            float d = fabs(hls_output[i] - expected_output[i]);
            l2 += d * d;
            if (d > max_diff) max_diff = d;
        }
        l2 = sqrt(l2);
        total_l2 += l2;

        bool pred_correct = (hls_pred == true_label);
        if (pred_correct) correct++;
        if (hls_pred == pt_pred) hls_pt_match++;

        printf("  HLS  pred=%d, PyT pred=%d, true=%d  %s%s\n",
               hls_pred, pt_pred, true_label,
               pred_correct ? "PASS" : "FAIL",
               pred_correct && hls_pred == pt_pred ? "" : " (check)");

        // Print full output if there's disagreement
        if (l2 > 0.01f) {
            printf("  HLS out: ");
            for (int i = 0; i < NUM_CLASSES; i++) printf("%+.4f ", hls_output[i]);
            printf("\n  PyT out: ");
            for (int i = 0; i < NUM_CLASSES; i++) printf("%+.4f ", expected_output[i]);
            printf("\n");
        }
        printf("  L2=%.4f, max_diff=%.4f\n", l2, max_diff);
    }

    printf("\n============================================================\n");
    printf("RESULTS (T=%d):\n", T_STEPS);
    printf("  Accuracy:    %d/%d (%.1f%%)\n", correct, NUM_IMAGES, 100.0 * correct / NUM_IMAGES);
    printf("  HLS==PyT:    %d/%d (%.1f%%)\n", hls_pt_match, NUM_IMAGES, 100.0 * hls_pt_match / NUM_IMAGES);
    printf("  Avg L2:      %.4f\n", total_l2 / NUM_IMAGES);
    printf("============================================================\n");

    free(input_buf);
    free(ddr);
    return (correct == NUM_IMAGES && hls_pt_match == NUM_IMAGES) ? 0 : 1;
}
